function topic([slug = "", title = "", summary = ""]: string[]): ProcedureTopic {
  return { slug, title, summary };
}

function makeSeed(domain: ProcedureDomain, topicItem: ProcedureTopic): ProcedureSeedInput {
  return {
    slug: `${domain.slugPrefix}-${topicItem.slug}`,
    title: topicItem.title,
    category: domain.category,
    summary: topicItem.summary,
    cost: domain.cost,
    duration: domain.duration,
    channel: domain.channel,
    documents: domain.documents,
    sources: domain.sources,
    warning: domain.warning
  };
}

export const nationalProcedureSeeds: ProcedureSeedInput[] = domains.flatMap((domain) =>
  domain.topics.map((topicItem) => makeSeed(domain, topicItem))
);
